#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct Node {
    int val;
    struct Node *left;
    struct Node *right;
} Node;

// Global array to map a value (≤100000) to its node pointer
static Node *nodeMap[100001];
static bool isChild[100001];

Node* getNode(int v) {
    if (nodeMap[v] == NULL) {
        nodeMap[v] = (Node*)malloc(sizeof(Node));
        nodeMap[v]->val = v;
        nodeMap[v]->left = nodeMap[v]->right = NULL;
    }
    return nodeMap[v];
}

bool dfs(Node* root, int target, int *seen, int *cnt) {
    if (!root) return false;
    int need = target - root->val;
    for (int i = 0; i < *cnt; ++i) if (seen[i] == need) return true;
    seen[(*cnt)++] = root->val;
    return dfs(root->left, target, seen, cnt) || dfs(root->right, target, seen, cnt);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, S; scanf("%d %d", &N, &S);
        // reset maps for this test case
        for (int i = 0; i <= 100000; ++i) {
            nodeMap[i] = NULL; isChild[i] = false;
        }
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            Node *parent = getNode(p);
            Node *child  = getNode(c);
            if (dir == 'L') parent->left = child; else parent->right = child;
            isChild[c] = true;
        }
        // find root (the node that never appeared as child)
        Node *root = NULL;
        for (int i = 0; i <= 100000; ++i) {
            if (nodeMap[i] && !isChild[i]) { root = nodeMap[i]; break; }
        }
        int seen[10000]; int cnt = 0;
        bool ok = dfs(root, S, seen, &cnt);
        printf(ok ? "YES\n" : "NO\n");
        // free allocated nodes (optional for contest environment)
        for (int i = 0; i <= 100000; ++i) if (nodeMap[i]) free(nodeMap[i]);
    }
    return 0;
}

