import java.io.*;
import java.util.*;

class Node {
    int val;
    Node left, right;
    Node(int v){val=v;}
}

public class Main {
    static Node getNode(Map<Integer, Node> map, int v) {
        return map.computeIfAbsent(v, k -> new Node(k));
    }

    static boolean dfs(Node cur, int target, Set<Integer> seen) {
        if (cur == null) return false;
        int need = target - cur.val;
        if (seen.contains(need)) return true;
        seen.add(cur.val);
        return dfs(cur.left, target, seen) || dfs(cur.right, target, seen);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int S = Integer.parseInt(st.nextToken());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                Node parent = getNode(map, p);
                Node child = getNode(map, c);
                if (dir == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            for (int v : map.keySet()) {
                if (!childSet.contains(v)) { root = map.get(v); break; }
            }
            Set<Integer> seen = new HashSet<>();
            boolean ok = dfs(root, S, seen);
            System.out.println(ok ? "YES" : "NO");
        }
    }
}

