import sys

def get_node(nodes, v):
    if v not in nodes:
        nodes[v] = [v, None, None]  # [val, left, right]
    return nodes[v]

def dfs(node, target, seen):
    if node is None:
        return False
    val, left, right = node
    need = target - val
    if need in seen:
        return True
    seen.add(val)
    return dfs(left, target, seen) or dfs(right, target, seen)

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N, S = map(int, next(it).split())
        nodes = {}
        children = set()
        for _ in range(N-1):
            p, c, d = next(it).split()
            p = int(p); c = int(c)
            parent = get_node(nodes, p)
            child = get_node(nodes, c)
            if d == 'L':
                parent[1] = child
            else:
                parent[2] = child
            children.add(c)
        root = None
        for v in nodes:
            if v not in children:
                root = nodes[v]
                break
        seen = set()
        ok = dfs(root, S, seen)
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

